"use client";

import * as React from "react";
import {
  Container,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Statistic,
  DistributionBar,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  SearchInput,
  Select,
  Button,
  Badge,
  Separator,
  DataTable,
  EmptyState,
  Grid,
  HStack,
  VStack,
  type ColumnDef,
} from "@gunjo/ui";
import {
  IconUserSearch,
  IconLayoutGrid,
  IconList,
  IconSitemap,
  IconFilterOff,
} from "@tabler/icons-react";
import {
  employees,
  DEPARTMENTS,
  EMPLOYMENT_TYPES,
  STATUSES,
  averageTenureYears,
  countByEmploymentType,
  type Employee,
} from "./data";
import { PersonCell, StatusBadge, EmploymentBadge } from "./PersonCell";
import { OrgChart } from "./OrgChart";
import { EmployeeDetail } from "./EmployeeDetail";

const ALL = "__all__";

export default function EmployeeDirectoryPage() {
  const [query, setQuery] = React.useState("");
  const [dept, setDept] = React.useState<string>(ALL);
  const [empType, setEmpType] = React.useState<string>(ALL);
  const [status, setStatus] = React.useState<string>(ALL);

  const [openId, setOpenId] = React.useState<string | null>(null);
  const [sheetOpen, setSheetOpen] = React.useState(false);

  const openEmployee = React.useCallback((id: string) => {
    setOpenId(id);
    setSheetOpen(true);
  }, []);

  const filtered = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    return employees.filter((e) => {
      if (dept !== ALL && !e.departmentPath.includes(dept) && e.department !== dept)
        return false;
      if (empType !== ALL && e.employmentType !== empType) return false;
      if (status !== ALL && e.status !== status) return false;
      if (q) {
        const hay = `${e.name}${e.kana}${e.department}${e.title}`.toLowerCase();
        if (!hay.includes(q)) return false;
      }
      return true;
    });
  }, [query, dept, empType, status]);

  const activeFilters = [
    dept !== ALL ? { key: "dept", label: `部署: ${dept}`, clear: () => setDept(ALL) } : null,
    empType !== ALL
      ? { key: "empType", label: `雇用形態: ${empType}`, clear: () => setEmpType(ALL) }
      : null,
    status !== ALL
      ? { key: "status", label: `ステータス: ${status}`, clear: () => setStatus(ALL) }
      : null,
    query.trim()
      ? { key: "q", label: `検索: ${query.trim()}`, clear: () => setQuery("") }
      : null,
  ].filter(Boolean) as { key: string; label: string; clear: () => void }[];

  const resetAll = () => {
    setQuery("");
    setDept(ALL);
    setEmpType(ALL);
    setStatus(ALL);
  };

  const byType = countByEmploymentType();
  const avgTenure = averageTenureYears();

  const columns = React.useMemo<ColumnDef<Employee>[]>(
    () => [
      {
        accessorKey: "name",
        header: "氏名",
        // 部署/役職は専用カラムがあるので、行内のメタ重複は抑制
        cell: ({ row }) => <PersonCell employee={row.original} showMeta={false} />,
      },
      {
        accessorKey: "department",
        header: "部署",
        cell: ({ row }) => (
          <span className="text-sm text-foreground">{row.original.department}</span>
        ),
      },
      {
        accessorKey: "title",
        header: "役職",
        cell: ({ row }) => (
          <span className="text-sm text-foreground">{row.original.title}</span>
        ),
      },
      {
        accessorKey: "employmentType",
        header: "雇用形態",
        cell: ({ row }) => <EmploymentBadge type={row.original.employmentType} />,
      },
      {
        accessorKey: "location",
        header: "勤務地",
        cell: ({ row }) => (
          <span className="text-sm text-muted-foreground">{row.original.location}</span>
        ),
      },
      {
        accessorKey: "joinedAt",
        header: "入社日",
        cell: ({ row }) => (
          <span className="text-sm tabular-nums text-muted-foreground">
            {row.original.joinedAt}
          </span>
        ),
      },
      {
        accessorKey: "status",
        header: "在籍",
        cell: ({ row }) => <StatusBadge status={row.original.status} />,
      },
    ],
    []
  );

  return (
    <main className="min-h-screen bg-background py-6">
      <Container size="xl">
        <VStack gap={6} align="stretch">
          {/* ヘッダ */}
          <header className="space-y-1">
            <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
              アオイテック株式会社・人事部
            </p>
            <h1 className="text-2xl font-bold tracking-tight text-foreground">
              従業員名簿 / 組織図
            </h1>
            <p className="text-sm text-muted-foreground">
              全社の従業員を一覧で見て、組織をたどり、個人の詳細を確認できます。
            </p>
          </header>

          {/* ヘッドカウントサマリ */}
          <section aria-label="ヘッドカウントサマリ">
            <Grid cols={{ base: 1, sm: 2, lg: 4 }} gap={4}>
              <Statistic
                label="総従業員数"
                value={`${employees.length} 名`}
                hint="正社員・契約・委託・パート含む"
              />
              <Statistic
                label="部署数"
                value={`${DEPARTMENTS.length}`}
                hint="本部・部・課を含む組織単位"
              />
              <Statistic
                label="平均勤続年数"
                value={`${avgTenure} 年`}
                hint="全従業員の単純平均"
              />
              <Statistic
                label="正社員比率"
                value={`${Math.round((byType.正社員 / employees.length) * 100)}%`}
                hint={`正社員 ${byType.正社員} 名`}
              />
            </Grid>
          </section>

          {/* 雇用形態別内訳 */}
          <Card>
            <CardHeader>
              <CardTitle as="h2" className="text-base">
                雇用形態別内訳
              </CardTitle>
              <CardDescription>クリックで各形態の人数構成を確認</CardDescription>
            </CardHeader>
            <CardContent>
              <DistributionBar
                showLegend
                totalLabel="合計"
                formatValue={(v) => `${v} 名`}
                segments={[
                  { label: "正社員", value: byType.正社員, color: "primary" },
                  { label: "契約社員", value: byType.契約社員, color: "info" },
                  { label: "業務委託", value: byType.業務委託, color: "accent" },
                  { label: "パート", value: byType.パート, color: "warning" },
                ]}
                aria-label="雇用形態別の人数構成"
              />
            </CardContent>
          </Card>

          {/* フィルタ + 検索 */}
          <Card>
            <CardContent className="space-y-4 p-4 sm:p-6">
              <div className="grid grid-cols-1 gap-3 md:grid-cols-2 lg:grid-cols-4">
                <SearchInput
                  value={query}
                  onValueChange={setQuery}
                  placeholder="氏名・ふりがな・部署で検索"
                  aria-label="従業員を検索"
                />
                <Select
                  label="部署"
                  value={dept}
                  onChange={(e) => setDept(e.target.value)}
                >
                  <option value={ALL}>すべての部署</option>
                  {DEPARTMENTS.map((d) => (
                    <option key={d} value={d}>
                      {d}
                    </option>
                  ))}
                </Select>
                <Select
                  label="雇用形態"
                  value={empType}
                  onChange={(e) => setEmpType(e.target.value)}
                >
                  <option value={ALL}>すべての雇用形態</option>
                  {EMPLOYMENT_TYPES.map((t) => (
                    <option key={t} value={t}>
                      {t}
                    </option>
                  ))}
                </Select>
                <Select
                  label="在籍ステータス"
                  value={status}
                  onChange={(e) => setStatus(e.target.value)}
                >
                  <option value={ALL}>すべてのステータス</option>
                  {STATUSES.map((s) => (
                    <option key={s} value={s}>
                      {s}
                    </option>
                  ))}
                </Select>
              </div>

              {activeFilters.length > 0 && (
                <>
                  <Separator />
                  <HStack gap={2} wrap align="center">
                    <span className="text-xs text-muted-foreground">適用中:</span>
                    {activeFilters.map((f) => (
                      <Badge key={f.key} variant="secondary" onRemove={f.clear}>
                        {f.label}
                      </Badge>
                    ))}
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={resetAll}
                      className="ml-auto"
                    >
                      <IconFilterOff className="mr-1 h-4 w-4" aria-hidden />
                      クリア
                    </Button>
                  </HStack>
                </>
              )}
            </CardContent>
          </Card>

          {/* ビュー切替: 一覧 / グリッド / 組織図 */}
          <Tabs defaultValue="list">
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
              <TabsList>
                <TabsTrigger value="list">
                  <IconList className="mr-1.5 h-4 w-4" aria-hidden />
                  一覧
                </TabsTrigger>
                <TabsTrigger value="grid">
                  <IconLayoutGrid className="mr-1.5 h-4 w-4" aria-hidden />
                  グリッド
                </TabsTrigger>
                <TabsTrigger value="org">
                  <IconSitemap className="mr-1.5 h-4 w-4" aria-hidden />
                  組織図
                </TabsTrigger>
              </TabsList>
              <p className="text-sm text-muted-foreground" aria-live="polite">
                {filtered.length} 名を表示中（全 {employees.length} 名）
              </p>
            </div>

            {/* 一覧（テーブル） */}
            <TabsContent value="list" className="px-0">
              {filtered.length === 0 ? (
                <NoResults onReset={resetAll} />
              ) : (
                <DataTable
                  columns={columns}
                  data={filtered}
                  pageSize={10}
                  onRowClick={(row) => openEmployee(row.id)}
                  renderCard={(row) => (
                    <button
                      type="button"
                      onClick={() => openEmployee(row.id)}
                      className="w-full rounded-lg border border-border bg-card p-3 text-left transition hover:bg-muted focus:outline-none focus:ring-2 focus:ring-ring"
                    >
                      <PersonCell employee={row} showStatus />
                      <div className="mt-2 flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
                        <EmploymentBadge type={row.employmentType} />
                        <span>{row.location}</span>
                        <span className="tabular-nums">入社 {row.joinedAt}</span>
                      </div>
                    </button>
                  )}
                />
              )}
            </TabsContent>

            {/* グリッド（カード） */}
            <TabsContent value="grid" className="px-0">
              {filtered.length === 0 ? (
                <NoResults onReset={resetAll} />
              ) : (
                <Grid cols={{ base: 1, sm: 2, lg: 3 }} gap={4}>
                  {filtered.map((e) => (
                    <EmployeeGridCard
                      key={e.id}
                      employee={e}
                      onOpen={() => openEmployee(e.id)}
                    />
                  ))}
                </Grid>
              )}
            </TabsContent>

            {/* 組織図（ツリー） */}
            <TabsContent value="org" className="px-0">
              <Card>
                <CardHeader>
                  <CardTitle as="h2" className="text-base">
                    組織図
                  </CardTitle>
                  <CardDescription>
                    会社 → 役員 → 本部 → 部 → 課 → 個人。行をクリックで詳細、▸ で展開。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <OrgChart onOpenEmployee={openEmployee} selectedId={openId ?? undefined} />
                </CardContent>
              </Card>
            </TabsContent>
          </Tabs>
        </VStack>
      </Container>

      <EmployeeDetail
        employeeId={openId}
        open={sheetOpen}
        onOpenChange={setSheetOpen}
        onNavigate={(id) => setOpenId(id)}
      />
    </main>
  );
}

function EmployeeGridCard({
  employee,
  onOpen,
}: {
  employee: Employee;
  onOpen: () => void;
}) {
  return (
    <Card className="transition hover:border-foreground/30 hover:shadow-md">
      <button
        type="button"
        onClick={onOpen}
        className="flex flex-col gap-3 p-4 text-left focus:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        aria-label={`${employee.name} の詳細を開く`}
      >
        <PersonCell employee={employee} showStatus />
        <Separator />
        <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
          <dt className="text-muted-foreground">雇用形態</dt>
          <dd className="text-foreground">
            <EmploymentBadge type={employee.employmentType} />
          </dd>
          <dt className="text-muted-foreground">勤務地</dt>
          <dd className="text-foreground">{employee.location}</dd>
          <dt className="text-muted-foreground">入社日</dt>
          <dd className="tabular-nums text-foreground">{employee.joinedAt}</dd>
        </dl>
      </button>
    </Card>
  );
}

function NoResults({ onReset }: { onReset: () => void }) {
  return (
    <EmptyState
      icon={<IconUserSearch className="h-6 w-6" aria-hidden />}
      title="該当する従業員が見つかりません"
      description="検索語やフィルタ条件を変えてお試しください。"
      action={
        <Button variant="outline" onClick={onReset}>
          <IconFilterOff className="mr-1 h-4 w-4" aria-hidden />
          フィルタをクリア
        </Button>
      }
    />
  );
}

"use client";

import * as React from "react";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  Avatar,
  AvatarFallback,
  AvatarImage,
  Badge,
  Tag,
  Separator,
  MetadataList,
  Timeline,
  TimelineItem,
  Button,
  HStack,
  VStack,
} from "@gunjo/ui";
import {
  IconMail,
  IconPhone,
  IconMapPin,
  IconCalendarEvent,
  IconArrowUp,
  IconUserCircle,
  IconAlertTriangle,
} from "@tabler/icons-react";
import {
  getEmployeeById,
  getDirectReports,
  tenureYears,
  type Employee,
} from "./data";
import { StatusBadge, EmploymentBadge, PersonCell } from "./PersonCell";

// TimelineTime / TimelineHeader 等のサブコンポーネントがバレルに無いので、
// TimelineItem の children に素のマークアップで日付+内容を入れる。
function MoveRow({ date, label, last }: { date: string; label: string; last: boolean }) {
  return (
    <TimelineItem connector={!last} variant={last ? "active" : "muted"}>
      <div className="pb-4">
        <p className="text-xs font-medium tabular-nums text-muted-foreground">{date}</p>
        <p className="text-sm text-foreground">{label}</p>
      </div>
    </TimelineItem>
  );
}

export function EmployeeDetail({
  employeeId,
  open,
  onOpenChange,
  onNavigate,
}: {
  employeeId: string | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  /** 上司・部下セルから別の従業員へドリル移動 */
  onNavigate: (id: string) => void;
}) {
  const employee = employeeId ? getEmployeeById(employeeId) : undefined;

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="right"
        className="w-full overflow-y-auto sm:max-w-md"
        aria-describedby={undefined}
      >
        {employee ? (
          <DetailBody employee={employee} onNavigate={onNavigate} />
        ) : (
          <SheetHeader>
            <SheetTitle>従業員が見つかりません</SheetTitle>
          </SheetHeader>
        )}
      </SheetContent>
    </Sheet>
  );
}

function DetailBody({
  employee,
  onNavigate,
}: {
  employee: Employee;
  onNavigate: (id: string) => void;
}) {
  const manager = employee.managerId ? getEmployeeById(employee.managerId) : undefined;
  const reports = getDirectReports(employee.id);

  return (
    <div className="space-y-6">
      <SheetHeader className="space-y-4">
        <HStack gap={4} align="start">
          <Avatar
            className="h-16 w-16"
            presence={employee.presence}
          >
            {employee.avatar ? <AvatarImage src={employee.avatar} alt="" /> : null}
            <AvatarFallback className="text-lg">{employee.initials}</AvatarFallback>
          </Avatar>
          <div className="min-w-0 flex-1">
            <SheetTitle className="truncate text-left">{employee.name}</SheetTitle>
            <SheetDescription className="text-left">
              {employee.kana}
            </SheetDescription>
            <p className="mt-1 text-sm text-foreground">
              {employee.department}・{employee.title}
            </p>
            <HStack gap={2} wrap className="mt-2">
              <StatusBadge status={employee.status} />
              <EmploymentBadge type={employee.employmentType} />
            </HStack>
          </div>
        </HStack>
      </SheetHeader>

      <Separator />

      {/* プロフィール / 基本情報 */}
      <section aria-labelledby="detail-profile" className="space-y-3">
        <h3 id="detail-profile" className="text-sm font-semibold text-foreground">
          基本情報
        </h3>
        <MetadataList
          items={[
            {
              label: "入社日",
              value: employee.joinedAt,
              description: `勤続 ${tenureYears(employee.joinedAt)} 年`,
              icon: <IconCalendarEvent className="h-4 w-4" aria-hidden />,
            },
            {
              label: "勤務地",
              value: employee.location,
              icon: <IconMapPin className="h-4 w-4" aria-hidden />,
            },
            {
              label: "メール",
              value: employee.email,
              icon: <IconMail className="h-4 w-4" aria-hidden />,
            },
            {
              label: "電話",
              value: employee.phone,
              icon: <IconPhone className="h-4 w-4" aria-hidden />,
            },
          ]}
        />
      </section>

      <Separator />

      {/* スキル / 資格 */}
      <section aria-labelledby="detail-skills" className="space-y-3">
        <h3 id="detail-skills" className="text-sm font-semibold text-foreground">
          スキル・資格
        </h3>
        <HStack gap={2} wrap>
          {employee.skills.map((s) => (
            <Tag key={s} variant="outline">
              {s}
            </Tag>
          ))}
        </HStack>
      </section>

      <Separator />

      {/* 直属の上司と部下 */}
      <section aria-labelledby="detail-reporting" className="space-y-3">
        <h3 id="detail-reporting" className="text-sm font-semibold text-foreground">
          レポートライン
        </h3>
        <div className="space-y-2">
          <p className="flex items-center gap-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            <IconArrowUp className="h-3 w-3" aria-hidden /> 直属の上司
          </p>
          {manager ? (
            <button
              type="button"
              onClick={() => onNavigate(manager.id)}
              className="w-full rounded-md border border-border bg-card p-2 text-left transition hover:bg-muted focus:outline-none focus:ring-2 focus:ring-ring"
              aria-label={`上司 ${manager.name} の詳細を開く`}
            >
              <PersonCell employee={manager} size="sm" />
            </button>
          ) : (
            <p className="text-sm text-muted-foreground">なし（最上位）</p>
          )}
        </div>
        <div className="space-y-2">
          <p className="flex items-center gap-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            <IconUserCircle className="h-3 w-3" aria-hidden /> 直属の部下（{reports.length}）
          </p>
          {reports.length ? (
            <VStack gap={2}>
              {reports.map((r) => (
                <button
                  key={r.id}
                  type="button"
                  onClick={() => onNavigate(r.id)}
                  className="w-full rounded-md border border-border bg-card p-2 text-left transition hover:bg-muted focus:outline-none focus:ring-2 focus:ring-ring"
                  aria-label={`部下 ${r.name} の詳細を開く`}
                >
                  <PersonCell employee={r} size="sm" />
                </button>
              ))}
            </VStack>
          ) : (
            <p className="text-sm text-muted-foreground">なし</p>
          )}
        </div>
      </section>

      <Separator />

      {/* 所属・異動履歴 */}
      <section aria-labelledby="detail-moves" className="space-y-3">
        <h3 id="detail-moves" className="text-sm font-semibold text-foreground">
          所属・異動履歴
        </h3>
        <Timeline>
          {[...employee.moves].reverse().map((m, i, arr) => (
            <MoveRow
              key={`${m.date}-${i}`}
              date={m.date}
              label={m.label}
              last={i === arr.length - 1}
            />
          ))}
        </Timeline>
      </section>

      <Separator />

      {/* 緊急連絡先 */}
      <section aria-labelledby="detail-emergency" className="space-y-3">
        <h3
          id="detail-emergency"
          className="flex items-center gap-1 text-sm font-semibold text-foreground"
        >
          <IconAlertTriangle className="h-4 w-4 text-warning" aria-hidden />
          緊急連絡先
        </h3>
        <MetadataList
          items={[
            { label: "氏名", value: employee.emergencyContact.name },
            { label: "続柄", value: employee.emergencyContact.relation },
            { label: "電話", value: employee.emergencyContact.phone },
          ]}
        />
      </section>

      <div className="pt-2">
        <Button variant="outline" className="w-full" asChild>
          <a href={`mailto:${employee.email}`}>
            <IconMail className="mr-2 h-4 w-4" aria-hidden />
            メールを送る
          </a>
        </Button>
      </div>
    </div>
  );
}

"use client";

import * as React from "react";
import { TreeView, type TreeNode, Badge, Button } from "@gunjo/ui";
import {
  IconChevronRight,
  IconUsers,
} from "@tabler/icons-react";
import { employees, getDirectReports, type Employee } from "./data";

// 会社 → 本部 → 部 → 課/チーム → 個人 の階層を、上司-部下関係から構築する。
// 役職を持つマネージャーの配下にレポートをぶら下げ、人がそのままツリーノードになる。

function buildPersonNode(emp: Employee, onOpen: (id: string) => void): TreeNode {
  const reports = getDirectReports(emp.id);
  return {
    id: emp.id,
    label: (
      <span className="flex min-w-0 items-center gap-2">
        <span className="truncate font-medium text-foreground">{emp.name}</span>
        <span className="truncate text-xs text-muted-foreground">{emp.title}</span>
      </span>
    ),
    icon: <IconUsers className="h-4 w-4 text-muted-foreground" aria-hidden />,
    children: reports.length
      ? reports.map((r) => buildPersonNode(r, onOpen))
      : undefined,
  };
}

export function buildOrgNodes(onOpen: (id: string) => void): TreeNode[] {
  const roots = employees.filter((e) => e.managerId === null);
  return [
    {
      id: "company",
      label: <span className="font-semibold text-foreground">アオイテック株式会社</span>,
      children: roots.map((r) => buildPersonNode(r, onOpen)),
    },
  ];
}

// 全 id を集めてデフォルト展開（最初は会社 + 役員層まで開く）
function topLevelIds(): string[] {
  const ids = ["company"];
  for (const e of employees) {
    if (e.managerId === null) ids.push(e.id);
  }
  return ids;
}

export function OrgChart({
  onOpenEmployee,
  selectedId,
}: {
  onOpenEmployee: (id: string) => void;
  selectedId?: string;
}) {
  const nodes = React.useMemo(() => buildOrgNodes(onOpenEmployee), [onOpenEmployee]);
  const allIds = React.useMemo(() => {
    const ids: string[] = ["company"];
    for (const e of employees) ids.push(e.id);
    return ids;
  }, []);
  const [expanded, setExpanded] = React.useState<Set<string>>(
    () => new Set(topLevelIds())
  );

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-end gap-2">
        <Button
          variant="ghost"
          size="sm"
          onClick={() => setExpanded(new Set(allIds))}
        >
          すべて展開
        </Button>
        <Button
          variant="ghost"
          size="sm"
          onClick={() => setExpanded(new Set(["company"]))}
        >
          すべて折りたたむ
        </Button>
      </div>
      <TreeView
        nodes={nodes}
        expanded={expanded}
        onExpandedChange={setExpanded}
        selectionMode="single"
        selectedId={selectedId}
        onSelectedIdChange={(id) => {
          if (id !== "company") onOpenEmployee(id);
        }}
        aria-label="組織図"
        renderNodeMeta={(node) => {
          if (node.id === "company") {
            return (
              <Badge variant="outline">{employees.length}名</Badge>
            );
          }
          const reports = getDirectReports(node.id);
          if (reports.length === 0) return null;
          return (
            <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
              <IconUsers className="h-3 w-3" aria-hidden />
              {reports.length}
            </span>
          );
        }}
        renderNodeActions={(node) =>
          node.id === "company" ? null : (
            <span
              className="inline-flex items-center text-xs text-muted-foreground opacity-0 transition group-hover:opacity-100"
              aria-hidden
            >
              詳細
              <IconChevronRight className="h-3 w-3" />
            </span>
          )
        }
      />
    </div>
  );
}

"use client";

import * as React from "react";
import {
  Avatar,
  AvatarFallback,
  AvatarImage,
  Badge,
  HStack,
  VStack,
} from "@gunjo/ui";
import {
  IconBriefcase,
  IconClockPause,
  IconLogout2,
} from "@tabler/icons-react";
import type { Employee, EmployeeStatus } from "./data";

// 在籍ステータス → Badge の色とアイコン（色だけに依存しないよう必ずアイコン+ラベル）
export const STATUS_META: Record<
  EmployeeStatus,
  { variant: "success" | "warning" | "destructive"; icon: React.ReactNode }
> = {
  在籍: { variant: "success", icon: <IconBriefcase className="h-3 w-3" aria-hidden /> },
  休職中: { variant: "warning", icon: <IconClockPause className="h-3 w-3" aria-hidden /> },
  退職予定: { variant: "destructive", icon: <IconLogout2 className="h-3 w-3" aria-hidden /> },
};

export function StatusBadge({ status }: { status: EmployeeStatus }) {
  const meta = STATUS_META[status];
  return (
    <Badge variant={meta.variant} icon={meta.icon}>
      {status}
    </Badge>
  );
}

export function EmploymentBadge({ type }: { type: Employee["employmentType"] }) {
  // 正社員は控えめ、非正規は outline で識別
  return (
    <Badge variant={type === "正社員" ? "secondary" : "outline"}>{type}</Badge>
  );
}

export interface PersonCellProps {
  employee: Employee;
  /** アバターサイズ。デフォルト md (h-10) */
  size?: "sm" | "md";
  /** 役職・部署などの副次情報を出すか。リストでは true、密なツリーでは false */
  showMeta?: boolean;
  /** 在籍ステータスのバッジを末尾に出すか */
  showStatus?: boolean;
}

/**
 * 「顔写真 + 氏名(+ふりがな) + 部署 + 役職 + 在籍ステータス」の人物セル。
 * @gunjo/ui に専用プリミティブが無いため Avatar + Badge + テキストを毎回手組みしている。
 */
export function PersonCell({
  employee,
  size = "md",
  showMeta = true,
  showStatus = false,
}: PersonCellProps) {
  const avatarSize = size === "sm" ? "h-8 w-8" : "h-10 w-10";
  return (
    <HStack gap={3} align="center" className="min-w-0">
      <Avatar
        className={avatarSize}
        presence={employee.presence}
        presenceLabel={presenceLabel(employee.presence)}
      >
        {employee.avatar ? (
          <AvatarImage src={employee.avatar} alt="" />
        ) : null}
        <AvatarFallback>{employee.initials}</AvatarFallback>
      </Avatar>
      <VStack gap={0} align="start" className="min-w-0">
        <HStack gap={2} align="baseline" wrap className="min-w-0">
          <span className="truncate text-sm font-medium text-foreground">
            {employee.name}
          </span>
          <span className="truncate text-xs text-muted-foreground">
            {employee.kana}
          </span>
        </HStack>
        {showMeta ? (
          <span className="truncate text-xs text-muted-foreground">
            {employee.department}・{employee.title}
          </span>
        ) : null}
      </VStack>
      {showStatus ? (
        <div className="ml-auto shrink-0">
          <StatusBadge status={employee.status} />
        </div>
      ) : null}
    </HStack>
  );
}

function presenceLabel(p: Employee["presence"]): string {
  switch (p) {
    case "online":
      return "オンライン";
    case "away":
      return "離席中";
    case "busy":
      return "取り込み中";
    case "offline":
      return "オフライン";
  }
}
